import{_ as e,o as l,c as t,a3 as i}from"./chunks/framework.BTFg6ESq.js";const p=JSON.parse('{"title":"日志管理器（移动端）","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/mobile/log-manager.md","filePath":"user-guide/mobile/log-manager.md","lastUpdated":1781934556000}'),o={name:"user-guide/mobile/log-manager.md"};function r(d,a,h,n,s,c){return l(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="日志管理器-移动端" tabindex="-1">日志管理器（移动端） <a class="header-anchor" href="#日志管理器-移动端" aria-label="Permalink to &quot;日志管理器（移动端）&quot;">​</a></h1><p>日志管理器用于查看移动端运行期间产生的日志。遇到请求失败、页面异常、配置没有生效时，它是最直接的排查入口。</p><h2 id="打开日志管理器" tabindex="-1">打开日志管理器 <a class="header-anchor" href="#打开日志管理器" aria-label="Permalink to &quot;打开日志管理器&quot;">​</a></h2><ol><li>在移动端首页点击「日志管理」。</li><li>页面顶部是搜索和级别筛选。</li><li>中间区域显示日志列表。</li><li>底部提供清空、导出、复制全部等操作。</li></ol><h2 id="搜索日志" tabindex="-1">搜索日志 <a class="header-anchor" href="#搜索日志" aria-label="Permalink to &quot;搜索日志&quot;">​</a></h2><p>在顶部搜索框输入关键词，可以按日志内容或模块名称过滤。例如：</p><ul><li><code>llm-api</code>：查看 LLM 服务相关日志。</li><li><code>llm-chat</code>：查看聊天相关日志。</li><li><code>ERROR</code>：配合级别筛选查找错误。</li><li>模型名或渠道名：定位某次请求。</li></ul><p>搜索会实时过滤当前内存中的日志。</p><h2 id="按级别筛选" tabindex="-1">按级别筛选 <a class="header-anchor" href="#按级别筛选" aria-label="Permalink to &quot;按级别筛选&quot;">​</a></h2><p>日志级别包括：</p><table tabindex="0"><thead><tr><th style="text-align:left;">级别</th><th style="text-align:left;">含义</th></tr></thead><tbody><tr><td style="text-align:left;">DEBUG</td><td style="text-align:left;">调试细节，适合开发和深入排查</td></tr><tr><td style="text-align:left;">INFO</td><td style="text-align:left;">正常流程记录</td></tr><tr><td style="text-align:left;">WARN</td><td style="text-align:left;">可恢复的问题或潜在风险</td></tr><tr><td style="text-align:left;">ERROR</td><td style="text-align:left;">已失败的操作或异常</td></tr></tbody></table><p>日常排查可以先选 <code>ERROR</code>，没有结果再切换到 <code>WARN</code> 或全部级别。</p><h2 id="自动滚动" tabindex="-1">自动滚动 <a class="header-anchor" href="#自动滚动" aria-label="Permalink to &quot;自动滚动&quot;">​</a></h2><p>开启自动滚动后，新日志出现时列表会滚到底部。它适合观察请求发送、模型响应或页面加载流程。</p><p>如果你正在阅读上方的旧日志，可以先关闭自动滚动，避免列表跳走。</p><h2 id="导出与复制" tabindex="-1">导出与复制 <a class="header-anchor" href="#导出与复制" aria-label="Permalink to &quot;导出与复制&quot;">​</a></h2><p>底部操作栏提供：</p><ul><li>清空日志：清除当前内存日志。</li><li>导出日志：下载文本文件，适合提交 issue 或长期保存。</li><li>复制全部：把当前日志文本复制到剪贴板，适合快速粘贴给开发者。</li></ul><p>提交问题时，请先检查日志中是否包含 API Key、私人路径、聊天内容等敏感信息，必要时手动删掉。</p><h2 id="常见排查流程" tabindex="-1">常见排查流程 <a class="header-anchor" href="#常见排查流程" aria-label="Permalink to &quot;常见排查流程&quot;">​</a></h2><h3 id="llm-请求失败" tabindex="-1">LLM 请求失败 <a class="header-anchor" href="#llm-请求失败" aria-label="Permalink to &quot;LLM 请求失败&quot;">​</a></h3><ol><li>清空日志。</li><li>回到 LLM 对话重新发送一条短消息。</li><li>打开日志管理器。</li><li>筛选 <code>ERROR</code>。</li><li>查看状态码、渠道名、模型名和错误消息。</li></ol><h3 id="配置保存后没生效" tabindex="-1">配置保存后没生效 <a class="header-anchor" href="#配置保存后没生效" aria-label="Permalink to &quot;配置保存后没生效&quot;">​</a></h3><ol><li>搜索配置模块名称。</li><li>查看是否出现保存成功日志。</li><li>返回对应工具重新进入，触发配置重新加载。</li><li>如果仍异常，导出日志并反馈。</li></ol><h3 id="页面卡住或空白" tabindex="-1">页面卡住或空白 <a class="header-anchor" href="#页面卡住或空白" aria-label="Permalink to &quot;页面卡住或空白&quot;">​</a></h3><ol><li>切到日志管理器。</li><li>查看最近的 <code>ERROR</code> 和 <code>WARN</code>。</li><li>记录触发路径：哪个页面、点击了哪个按钮、是否刚刚切换网络。</li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="清空日志会删除历史文件吗" tabindex="-1">清空日志会删除历史文件吗？ <a class="header-anchor" href="#清空日志会删除历史文件吗" aria-label="Permalink to &quot;清空日志会删除历史文件吗？&quot;">​</a></h3><p>移动端日志管理器主要管理当前运行期间的内存日志。清空后当前列表会变空，已经导出的文件不会被删除。</p><h3 id="为什么没有任何日志" tabindex="-1">为什么没有任何日志？ <a class="header-anchor" href="#为什么没有任何日志" aria-label="Permalink to &quot;为什么没有任何日志？&quot;">​</a></h3><p>可能是刚启动还没有触发操作，或当前筛选条件太严格。切换到全部级别，并清空搜索关键词再看。</p><h3 id="导出的日志在哪里" tabindex="-1">导出的日志在哪里？ <a class="header-anchor" href="#导出的日志在哪里" aria-label="Permalink to &quot;导出的日志在哪里？&quot;">​</a></h3><p>导出会走移动端 WebView 的下载能力，具体保存位置取决于系统和运行环境。如果不确定，使用「复制全部」通常更直接。</p><h3 id="日志里能看到-api-key-吗" tabindex="-1">日志里能看到 API Key 吗？ <a class="header-anchor" href="#日志里能看到-api-key-吗" aria-label="Permalink to &quot;日志里能看到 API Key 吗？&quot;">​</a></h3><p>正常情况下不应主动记录完整 Key，但不同错误返回可能包含敏感上下文。分享日志前请自行检查。</p>',35)])])}const b=e(o,[["render",r]]);export{p as __pageData,b as default};
